-- Replace recurring happy hours + trivia with the combined venue sheet.
-- Deletes the two current sources (all happy-hours + trivia-nights events) and
-- inserts 1568 instances (1308 happy hour, 260 trivia) generated from 120 venues
-- over the next 28 days. Safe to re-run. Paste into Supabase -> SQL Editor -> Run.
begin;
delete from public.events where category in ('happy-hours','trivia-nights');
commit;
